diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 6737b50405ee..d1f44375d002 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -2008,15 +2008,27 @@ Instruction *InstCombinerImpl::foldICmpAndConstant(ICmpInst &Cmp,
     Value *A;
     const APInt *Addend, *Msk;
     if (match(And, m_And(m_OneUse(m_Add(m_Value(A), m_APInt(Addend))),
-                         m_LowBitMask(Msk))) &&
-        C.ule(*Msk)) {
-      APInt NewComperand = (C - *Addend) & *Msk;
-      Value *MaskA = Builder.CreateAnd(A, ConstantInt::get(A->getType(), *Msk));
-      return new ICmpInst(Pred, MaskA,
-                          ConstantInt::get(MaskA->getType(), NewComperand));
+                         m_APInt(Msk)))) {
+      // If the mask is a low bit mask, we can safely fold.
+      if (Msk->isMask() && C.ule(*Msk)) {
+        APInt NewComperand = (C - *Addend) & *Msk;
+        Value *MaskA = Builder.CreateAnd(A, ConstantInt::get(A->getType(), *Msk));
+        return new ICmpInst(Pred, MaskA,
+                            ConstantInt::get(MaskA->getType(), NewComperand));
+      }
+      
+      // If C is 0, we can potentially fold if (Addend & Msk) == ((~Msk + Addend) & Msk).
+      if (C.isZero()) {
+        APInt NotMsk = ~*Msk;
+        if ((*Addend & *Msk) == ((NotMsk + *Addend) & *Msk)) {
+          APInt NewComperand = (-*Addend) & *Msk;
+          Value *MaskA = Builder.CreateAnd(A, ConstantInt::get(A->getType(), *Msk));
+          return new ICmpInst(Pred, MaskA,
+                              ConstantInt::get(MaskA->getType(), NewComperand));
+        }
+      }
     }
   }
-
   return nullptr;
 }

