# condition for ((X + C1) & C2) == 0 being equivalent to (X & C2) == (-C1 & C2)
# If we add C1 to X, and mask with C2.
# We want this to be 0.
# We notice that (-C1 & ~C2) must be 0? Let's check.
def check_property(c1, c2):
    for x in range(256):
        cond1 = (((x + c1) & 0xff) & c2) == 0
        val2 = (-c1) & 0xff
        cond2 = (x & c2) == (val2 & c2)
        if cond1 != cond2:
            return False
    return True

matches = []
for c1 in range(-128, 128):
    for c2 in range(256):
        c1u = c1 & 0xff
        if c2 != 0 and c1u != 0:
            if check_property(c1, c2):
                matches.append((c1u, c2, ~c2 & 0xff))

print("Total matches:", len(matches))

def implies_property(c1, c2):
    c1_neg = (-c1) & 0xff
    not_c2 = (~c2) & 0xff
    return (c1_neg & not_c2) == 0

for c1u, c2, not_c2 in matches:
    if not implies_property(c1u, c2):
        print(f"Oops: c1={c1u:02x}, c2={c2:02x}, ~c2={not_c2:02x}, c1_neg={(-c1u)&0xff:02x}")
