# So check_property(c1, c2) is EXACTLY EQUIVALENT to:
# For all Y, (( (-C1 & C2) | (Y & ~C2) ) + C1) & C2 == 0
def check_property(c1, c2):
    c1_neg = (-c1) & 0xff
    for y in range(256):
        x = (c1_neg & c2) | (y & ~c2)
        if (((x + c1) & 0xff) & c2) != 0:
            return False
    return True

matches = []
for c1 in range(256):
    for c2 in range(256):
        if c2 != 0 and c1 != 0:
            if check_property(c1, c2):
                matches.append((c1, c2))

# Now, we just need a closed-form bitwise check for this!
# We want: (( (-C1 & C2) | (Y & ~C2) ) + C1) & C2 == 0 for all Y.
# Notice that (-C1 & C2) | (Y & ~C2) is just X.
# We are adding C1.
# What is the minimum and maximum of this expression?
# If we just compute this for Y=0 and Y=~C2, is it enough?
def check_ends(c1, c2):
    c1_neg = (-c1) & 0xff
    not_c2 = (~c2) & 0xff

    x0 = (c1_neg & c2)
    x1 = (c1_neg & c2) | not_c2

    return ((((x0 + c1) & 0xff) & c2) == 0) and ((((x1 + c1) & 0xff) & c2) == 0)

missed = []
for c1 in range(256):
    for c2 in range(256):
        if c2 != 0 and c1 != 0:
            if check_ends(c1, c2) and not check_property(c1, c2):
                missed.append((c1, c2))
print("Missed:", len(missed))

